-- Insert 43 new isometrics exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Front Plank', 'front-plank', 'Front Plank is an isometric exercise using the prone forearm plank to develop core, spine, shoulder control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 20, 40, 60, 'Prone trunk hold that teaches anti-extension, rib-pelvis stacking, and whole-body tension without motion.', 'Primary subrole: trunk_pelvis_anti_movement_control. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Anti-extension trunk isometric', 'resilience', 'trunk_pelvis_anti_movement_control', 'front_plank_anti_extension_hold', '{"primary_joint_actions":["spine_anti_extension","shoulder_support","hip_extension_lock","pelvic_control"],"primary_tissues":["anterior_core","glutes","serratus_anterior","hip_flexors"],"primary_motor_control_demands":["rib_pelvis_stack","anti_extension","whole_body_tension"],"postural_shape":"prone forearm plank","breathing_demand":"quiet nasal or controlled open-glottis breathing","balance_demand":"stable floor support","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Set up in the prone forearm plank. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the prone forearm plank.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 20 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Long body, ribs down","Push the floor away","Squeeze glutes without holding breath"],"common_faults":["Hips sag or pike","Breath is held","Shoulders collapse toward ears"]}'::jsonb),
  ('Dead Bug Iso Press', 'dead-bug-iso-press', 'Dead Bug Iso Press is an isometric exercise using the supine dead bug with hand-to-knee pressure to develop core, spine, hip control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 10, 25, 35, 'Supine opposite-limb pressure drill that activates anterior core control while teaching breath under tension.', 'Primary subrole: activate. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Supine anti-extension isometric', 'prepare_and_access', 'activate', 'dead_bug_trunk_activation_hold', '{"primary_joint_actions":["spine_anti_extension","hip_flexion_isometric","shoulder_flexion_reach","pelvic_control"],"primary_tissues":["anterior_core","diaphragm","hip_flexors","serratus_anterior"],"primary_motor_control_demands":["contralateral_pressure","anti_extension","breath_under_brace"],"postural_shape":"supine dead bug with hand-to-knee pressure","breathing_demand":"long exhale with light brace, no breath hold","balance_demand":"stable supine","coordination_demand":"moderate contralateral control","impact_level":0}'::jsonb, '{"movement_description":"Set up in the supine dead bug with hand-to-knee pressure. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the supine dead bug with hand-to-knee pressure.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 10 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Press knee into hand and hand into knee","Keep the ribs heavy","Breathe through the pressure"],"common_faults":["Back arches off floor","Pressing too hard to breathe","Neck tension takes over"]}'::jsonb),
  ('Bear Hover Hold', 'bear-hover-hold', 'Bear Hover Hold is an isometric exercise using the quadruped hover with knees just off floor to develop core, shoulder, hip control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 15, 40, 55, 'Hands-and-feet hover that teaches crawling posture, trunk stiffness, and shoulder/hip organization.', 'Primary subrole: shape_position_intelligence. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Quadruped hover isometric', 'movement_intelligence', 'shape_position_intelligence', 'bear_hover_shape_hold', '{"primary_joint_actions":["spine_anti_extension","shoulder_support","hip_flexion","knee_hover_isometric","wrist_extension_support"],"primary_tissues":["anterior_core","serratus_anterior","quadriceps","hip_flexors"],"primary_motor_control_demands":["contralateral_crawl_shape","quiet_knee_hover","hand_foot_pressure"],"postural_shape":"quadruped hover with knees just off floor","breathing_demand":"steady breathing while keeping knees low","balance_demand":"four-point static support","coordination_demand":"moderate whole-body control","impact_level":0}'::jsonb, '{"movement_description":"Set up in the quadruped hover with knees just off floor. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the quadruped hover with knees just off floor.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 15 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Knees one inch off the floor","Push the ground away","Quiet back, quiet hips"],"common_faults":["Hips rise high","Shoulders collapse","Breath stops after the lift"]}'::jsonb),
  ('Glute Bridge Iso Hold', 'glute-bridge-iso-hold', 'Glute Bridge Iso Hold is an isometric exercise using the supine bridge top hold to develop hip, core, spine control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 15, 30, 45, 'Supine hip-extension hold that activates glutes while teaching pelvis position and hamstring-free hip drive.', 'Primary subrole: activate. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Hip-extension activation isometric', 'prepare_and_access', 'activate', 'glute_bridge_activation_hold', '{"primary_joint_actions":["hip_extension_isometric","pelvic_posterior_tilt","knee_flexion_hold","spine_neutral_control"],"primary_tissues":["glutes","hamstrings","anterior_core","adductors"],"primary_motor_control_demands":["glute_activation","pelvic_control","hip_extension_without_lumbar_extension"],"postural_shape":"supine bridge top hold","breathing_demand":"slow breathing without rib flare","balance_demand":"stable supine","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Set up in the supine bridge top hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the supine bridge top hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 15 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Tuck slightly, then bridge","Feel glutes, not low back","Hold the top and breathe"],"common_faults":["Overarching the low back","Hamstrings cramp from heel pull","Ribs flare at the top"]}'::jsonb),
  ('Suitcase Hold', 'suitcase-hold', 'Suitcase Hold is an isometric exercise using the standing tall with one load at side to develop core, forearm, shoulder control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 3, NULL, 20, 60, 80, 'Single-arm loaded standing hold that builds grip, shoulder packing, and trunk anti-lateral-flexion strength.', 'Primary subrole: carry_trunk_loaded_bracing_strength. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Anti-lateral-flexion loaded hold', 'capacity', 'carry_trunk_loaded_bracing_strength', 'suitcase_loaded_anti_lateral_flexion_hold', '{"primary_joint_actions":["spine_anti_lateral_flexion","shoulder_depression_retraction","grip_isometric","hip_stack_control"],"primary_tissues":["obliques","quadratus_lumborum","forearm_flexors","upper_back"],"primary_motor_control_demands":["loaded_posture","anti_lateral_flexion","grip_under_brace"],"postural_shape":"standing tall with one load at side","breathing_demand":"controlled open-glottis breathing under load","balance_demand":"stable stance with asymmetric load","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the standing tall with one load at side. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the standing tall with one load at side.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 20 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Stand tall like the weight is trying to bend you","Shoulders level","Crush the handle and breathe"],"common_faults":["Leaning away from the load","Grip fails before posture is trained","Holding breath to make the hold longer"]}'::jsonb),
  ('Split Squat Iso Hold', 'split-squat-iso-hold', 'Split Squat Iso Hold is an isometric exercise using the bottom or mid-range split-squat hold to develop hip, knee, ankle control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 20, 60, 80, 'Static split-squat hold that builds single-leg strength, hip control, and lower-body positional tolerance.', 'Primary subrole: squat_knee_dominant_strength. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Unilateral squat position isometric', 'capacity', 'squat_knee_dominant_strength', 'split_squat_iso_strength_hold', '{"primary_joint_actions":["front_knee_flexion_isometric","front_hip_flexion_isometric","rear_hip_extension","ankle_dorsiflexion_hold"],"primary_tissues":["quadriceps","glutes","adductors","calves"],"primary_motor_control_demands":["single_leg_alignment","pelvis_stack","front_foot_pressure"],"postural_shape":"bottom or mid-range split-squat hold","breathing_demand":"controlled breathing without trunk sway","balance_demand":"moderate split stance","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the bottom or mid-range split-squat hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the bottom or mid-range split-squat hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 20 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Front foot owns the ground","Back knee heavy, chest quiet","Hold the line before adding load"],"common_faults":["Front knee collapses inward","Torso dumps forward","Rear hip cramps or pinches"]}'::jsonb),
  ('Spanish Squat Hold', 'spanish-squat-hold', 'Spanish Squat Hold is an isometric exercise using the band-behind-knees squat hold to develop knee, hip, ankle control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 3, NULL, 20, 60, 80, 'Band-supported upright squat hold that loads the quadriceps while allowing the trunk to stay tall.', 'Primary subrole: slow_eccentric_isometric_joint_resilience. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Quad and tendon-friendly knee isometric', 'resilience', 'slow_eccentric_isometric_joint_resilience', 'spanish_squat_quad_tendon_hold', '{"primary_joint_actions":["knee_flexion_isometric","hip_flexion_control","ankle_dorsiflexion_hold","trunk_upright_bracing"],"primary_tissues":["quadriceps","patellar_tendon","glutes","adductors"],"primary_motor_control_demands":["upright_squat_position","knee_track","band_counterbalance_control"],"postural_shape":"band-behind-knees squat hold","breathing_demand":"steady breathing under quad tension","balance_demand":"stable but band-dependent","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the band-behind-knees squat hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the band-behind-knees squat hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for 