  ('Wall Drive Sprint Iso Hold', 'wall-drive-sprint-iso-hold', 'Wall Drive Sprint Iso Hold is an isometric exercise using the angled wall sprint-drive hold to develop ankle, hip, core control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 3, NULL, 6, 30, 36, 'Wall-supported sprint-position hold that teaches acceleration shin angle, trunk line, and aggressive ground projection without running volume.', 'Primary subrole: potentiate_bridge. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Acceleration posture isometric', 'prepare_and_access', 'potentiate_bridge', 'wall_drive_acceleration_iso_hold', '{"primary_joint_actions":["ankle_stiffness_isometric","hip_flexion_drive","support_leg_extension","shoulder_support"],"primary_tissues":["calves","glutes","hip_flexors","anterior_core"],"primary_motor_control_demands":["acceleration_angle","frontside_knee_drive","push_wall_without_collapsing"],"postural_shape":"angled wall sprint-drive hold","breathing_demand":"brief controlled breath, no straining","balance_demand":"supported split sprint stance","coordination_demand":"moderate sprint posture","impact_level":0}'::jsonb, '{"movement_description":"Set up in the angled wall sprint-drive hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the angled wall sprint-drive hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 6 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Push the wall away","Long line from heel to head","Knee punches up without rib flare"],"common_faults":["Hips drop toward the wall","Support heel collapses","Athlete turns it into a max-effort strain"]}'::jsonb),
  ('Snapdown Landing Stick', 'snapdown-landing-stick', 'Snapdown Landing Stick is an isometric exercise using the athletic landing stick from tall snapdown to develop ankle, knee, hip control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 3, NULL, 3, 30, 33, 'Quick drop to an athletic landing position followed by a clean static stick to teach braking and alignment.', 'Primary subrole: landing_braking_control. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Landing-braking isometric', 'resilience', 'landing_braking_control', 'snapdown_landing_stick_hold', '{"primary_joint_actions":["ankle_dorsiflexion_landing_hold","knee_flexion_hold","hip_flexion_hold","trunk_bracing"],"primary_tissues":["quadriceps","glutes","calves","adductors"],"primary_motor_control_demands":["quiet_contact","braking_alignment","stick_quality"],"postural_shape":"athletic landing stick from tall snapdown","breathing_demand":"exhale into landing, breathe during stick","balance_demand":"moderate dynamic to static","coordination_demand":"moderate","impact_level":1}'::jsonb, '{"movement_description":"Set up in the athletic landing stick from tall snapdown. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the athletic landing stick from tall snapdown.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 3 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Snap down, land quiet, freeze","Knees track, feet rooted","The stick is the rep"],"common_faults":["Landing loud or collapsing","Counting reps that wobble","Turning it into conditioning contacts"]}'::jsonb),
  ('Push-Up Bottom Iso Hold', 'push-up-bottom-iso-hold', 'Push-Up Bottom Iso Hold is an isometric exercise using the push-up bottom hold at owned depth to develop shoulder, elbow, wrist control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 3, NULL, 8, 60, 68, 'Bottom-position push-up hold that builds pressing strength, trunk stiffness, and shoulder range control.', 'Primary subrole: upper_body_push_strength. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Horizontal push position isometric', 'capacity', 'upper_body_push_strength', 'push_up_bottom_iso_strength_hold', '{"primary_joint_actions":["elbow_flexion_isometric","shoulder_horizontal_abduction_control","wrist_extension_support","spine_anti_extension"],"primary_tissues":["pectorals","triceps","anterior_deltoids","serratus_anterior"],"primary_motor_control_demands":["pressing_bottom_control","scapular_position","whole_body_line"],"postural_shape":"push-up bottom hold at owned depth","breathing_demand":"controlled breathing without sagging","balance_demand":"stable hand-foot support","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the push-up bottom hold at owned depth. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the push-up bottom hold at owned depth.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 8 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Body stays one piece","Elbows own the angle","Press the floor without rising"],"common_faults":["Shoulders dump forward","Hips sag","Athlete holds breath at the bottom"]}'::jsonb),
  ('Push-Up Top Lockout Hold', 'push-up-top-lockout-hold', 'Push-Up Top Lockout Hold is an isometric exercise using the high-plank top support hold to develop shoulder, wrist, core control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 15, 30, 45, 'Top push-up support hold that activates serratus, trunk stiffness, and wrist/shoulder support.', 'Primary subrole: activate. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Top-support plank isometric', 'prepare_and_access', 'activate', 'push_up_top_support_activation_hold', '{"primary_joint_actions":["elbow_extension_lockout","shoulder_protraction_support","wrist_extension_support","spine_anti_extension"],"primary_tissues":["serratus_anterior","triceps","anterior_core","forearm_flexors"],"primary_motor_control_demands":["top_support_line","scapular_push","brace_with_hand_pressure"],"postural_shape":"high-plank top support hold","breathing_demand":"steady breathing while pushing floor","balance_demand":"stable hand-foot support","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the high-plank top support hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the high-plank top support hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 15 seconds or the pres