  ('Scapular Push-Up Plus Iso Hold', 'scapular-push-up-plus-iso-hold', 'Scapular Push-Up Plus Iso Hold is an isometric exercise using the high plank with plus/protraction hold to develop shoulder, scapula, wrist control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 10, 30, 40, 'Protracted high-plank hold that teaches serratus activation and scapular support without elbow motion.', 'Primary subrole: activate. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Serratus activation isometric', 'prepare_and_access', 'activate', 'scapular_push_up_plus_activation_hold', '{"primary_joint_actions":["scapular_protraction_isometric","elbow_extension_hold","wrist_extension_support","spine_anti_extension"],"primary_tissues":["serratus_anterior","rotator_cuff","triceps","anterior_core"],"primary_motor_control_demands":["serratus_activation","scapular_wrap","rib_control_under_hand_support"],"postural_shape":"high plank with plus/protraction hold","breathing_demand":"steady breathing without rib flare","balance_demand":"stable hand-foot support","coordination_demand":"moderate scapular control","impact_level":0}'::jsonb, '{"movement_description":"Set up in the high plank with plus/protraction hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the high plank with plus/protraction hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 10 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Spread shoulder blades around ribs","Keep elbows straight","Do not shrug into ears"],"common_faults":["Elbows bend into a push-up","Ribs drop toward floor","Neck does the work"]}'::jsonb),
  ('Wall Push Overcoming Iso', 'wall-push-overcoming-iso', 'Wall Push Overcoming Iso is an isometric exercise using the split stance or square stance wall press to develop shoulder, elbow, wrist control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 4, NULL, 5, 75, 80, 'Max-intent but immovable wall press that trains push force at a fixed joint angle with low movement complexity.', 'Primary subrole: upper_body_push_strength. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Overcoming upper-body push isometric', 'capacity', 'upper_body_push_strength', 'wall_push_overcoming_iso_strength', '{"primary_joint_actions":["shoulder_horizontal_press_isometric","elbow_extension_isometric","wrist_neutral_press","trunk_bracing"],"primary_tissues":["pectorals","triceps","anterior_deltoids","serratus_anterior"],"primary_motor_control_demands":["gradual_force_ramp","whole_body_brace","fixed_angle_push_intent"],"postural_shape":"split stance or square stance wall press","breathing_demand":"brace with controlled exhale; avoid Valsalva","balance_demand":"stable stance","coordination_demand":"moderate intent control","impact_level":0}'::jsonb, '{"movement_description":"Set up in the split stance or square stance wall press. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the split stance or square stance wall press.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 5 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Ramp pressure smoothly","Push the wall, not your breath","Stop before posture changes"],"common_faults":["Sudden jerk into the wall","Breath holding and face strain","Hips twist to find leverage"]}'::jsonb),
  ('Isometric Doorframe Row', 'isometric-doorframe-row', 'Isometric Doorframe Row is an isometric exercise using the standing or leaned fixed-object row pull to develop shoulder, elbow, forearm control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 4, NULL, 6, 75, 81, 'Fixed-object pulling hold that builds rowing strength, grip, and scapular retraction at a chosen body angle.', 'Primary subrole: pull_hang_grip_strength. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Overcoming row isometric', 'capacity', 'pull_hang_grip_strength', 'doorframe_row_overcoming_iso', '{"primary_joint_actions":["shoulder_extension_row_isometric","elbow_flexion_isometric","scapular_retraction","trunk_bracing"],"primary_tissues":["lats","rhomboids","middle_traps","biceps","forearm_flexors"],"primary_motor_control_demands":["fixed_angle_pull","scapular_pack","brace_without_leaning_back"],"postural_shape":"standing or leaned fixed-object row pull","breathing_demand":"controlled breathing under pull tension","balance_demand":"stable stance","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Set up in the standing or leaned fixed-object row pull. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the standing or leaned fixed-object row pull.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as 