  ('Med Ball Squeeze Iso Hold', 'med-ball-squeeze-iso-hold', 'Med Ball Squeeze Iso Hold is an isometric exercise using the supine, seated, or standing ball squeeze hold to develop hip, core, shoulder control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 10, 20, 30, 'Light med-ball squeeze hold that activates adductors, chest, or midline tension depending on setup.', 'Primary subrole: activate. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Adductor/pec compression isometric', 'prepare_and_access', 'activate', 'med_ball_squeeze_activation_hold', '{"primary_joint_actions":["hip_adduction_isometric","shoulder_horizontal_adduction_isometric","trunk_bracing","pelvic_control"],"primary_tissues":["adductors","pectorals","anterior_core","glutes"],"primary_motor_control_demands":["midline_pressure","symmetrical_squeeze","breath_under_light_tension"],"postural_shape":"supine, seated, or standing ball squeeze hold","breathing_demand":"long exhales while maintaining light pressure","balance_demand":"stable","coordination_demand":"low","impact_level":0}'::jsonb, '{"movement_description":"Set up in the supine, seated, or standing ball squeeze hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the supine, seated, or standing ball squeeze hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 10 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Squeeze smoothly, not maximally","Keep ribs quiet","Hold pressure while breathing"],"common_faults":["Max effort creates cramps","Breath holding during a warm-up drill","Wrong setup for the intended tissue"]}'::jsonb),
  ('Bear Plank Shoulder Tap Iso Hold', 'bear-plank-shoulder-tap-iso-hold', 'Bear Plank Shoulder Tap Iso Hold is an isometric exercise using the bear hover with opposite shoulder tap hold to develop core, shoulder, wrist control, tissue tolerance, and force expression without visible joint movement.', 'BEGINNER', 8, 2, NULL, 8, 40, 48, 'Bear hover with one hand lightly touching the opposite shoulder, teaching anti-rotation and crawling position control.', 'Primary subrole: shape_position_intelligence. Coach exact joint angles, gradual tension, steady breathing, and a clean stop. Isometrics are useful only when the athlete owns the position rather than surviving the clock.', 'Own the position, build steady pressure, breathe, and stop before the shape changes.', 'Crawl-position anti-rotation isometric', 'movement_intelligence', 'shape_position_intelligence', 'bear_plank_shoulder_tap_iso_hold', '{"primary_joint_actions":["spine_anti_rotation","shoulder_support","wrist_extension_support","hip_knee_hover_hold"],"primary_tissues":["anterior_core","serratus_anterior","glutes","quadriceps"],"primary_motor_control_demands":["anti_rotation_in_bear","single_hand_support","quiet_pelvis"],"postural_shape":"bear hover with opposite shoulder tap hold","breathing_demand":"steady breathing while one hand support changes","balance_demand":"high hand-foot support challenge","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Set up in the bear hover with opposite shoulder tap hold. Create tension gradually, hold the exact position, breathe under control, and end the set before posture, pain-free range, or breathing quality breaks.","setup":["Set the athlete in the bear hover with opposite shoulder tap hold.","Choose the easiest variation that allows pain-free alignment and calm breathing.","Coach a gradual build of tension instead of a sudden jerk into the position."],"execution_steps":["Create the target body shape and confirm the key joints are aligned.","Build pressure into the floor, implement, wall, band, cable, bar, or body position as appropriate.","Hold for about 8 seconds or the prescribed effort window while breathing under control.","End the set as soon as alignment, breathing, pain-free range, or target-tissue tension changes."],"coach_cues":["Lift one hand without shifting hips","Knees hover low","Tap and freeze before switching"],"common_faults":["Hips sway side to side","Shoulder collapses on support arm","Turning it into fast shoulder taps"]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

