  ('isometric-ankle-inversion-press', FALSE, 4, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('isometric-ankle-eversion-press', FALSE, 4, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('foot-tripod-single-leg-balance-hold', FALSE, 6, 0, FALSE, FALSE, FALSE, FALSE, FALSE),
  ('big-toe-press-iso-hold', TRUE, 7, 0, FALSE, FALSE, FALSE, FALSE, FALSE),
  ('wall-drive-sprint-iso-hold', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('snapdown-landing-stick', FALSE, 3, 24, FALSE, FALSE, TRUE, TRUE, FALSE),
  ('push-up-bottom-iso-hold', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
