  ('wall-handstand-hold', FALSE, 3, 24, FALSE, FALSE, TRUE, TRUE, FALSE),
  ('overhead-dumbbell-hold', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
