  ('med-ball-squeeze-iso-hold', TRUE, 6, 0, FALSE, FALSE, FALSE, FALSE, FALSE),
  ('bear-plank-shoulder-tap-iso-hold', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE)
